**Playwright Kurulum:** `npm install playwright && npx playwright install`. ```js
const { chromium } = require('playwright');
(async () => {
  const b = await chromium.launch();
  const p = await b.newPage();
  await p.goto('https://site.com');
  await p.waitForSelector('.item');
  const data = await p.$$eval('.item', els => els.map(e => e.textContent));
  console.log(data);
  await b.close();
})();
``` Playwright > Selenium: hızlı, modern API, auto-wait.

**Puppeteer Snapshot:** ```js
const puppeteer = require('puppeteer');
(async () => {
  const browser = await puppeteer.launch();
  const page = await browser.newPage();
  await page.goto('https://site.com', {waitUntil:'networkidle2'});
  await page.screenshot({path:'shot.png', fullPage:true});
  await page.pdf({path:'page.pdf', format:'A4'});
  await browser.close();
})();
``` Ekran görüntüsü + PDF oluşturma + CSS enjeksiyonu + form doldurma.
